import React from 'react';

// Admin dashboard main page
// Provides navigation to user, order, and product management
export default function AdminDashboard({ onNavigate }) {
  return (
    <div className="min-h-screen bg-gray-50 p-8">
      <h1 className="text-3xl font-bold mb-8">Admin Dashboard</h1>
      <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
        <button onClick={() => onNavigate('user')} className="bg-white p-6 rounded-lg shadow hover:shadow-lg text-lg font-semibold text-green-700 border border-green-200 hover:bg-green-50">User Management</button>
        <button onClick={() => onNavigate('order')} className="bg-white p-6 rounded-lg shadow hover:shadow-lg text-lg font-semibold text-blue-700 border border-blue-200 hover:bg-blue-50">Order Management</button>
        <button onClick={() => onNavigate('product')} className="bg-white p-6 rounded-lg shadow hover:shadow-lg text-lg font-semibold text-yellow-700 border border-yellow-200 hover:bg-yellow-50">Product Management</button>
      </div>
    </div>
  );
}
